select t1.user_id, t1.CREATED_BY, t1.LAST_UPDATED_BY, t1.PUNISH, t1.FK_SUB_COL_ID, t1.PUNISH_CONTENT, t1.CREATION_DATE, t1.LAST_UPDATE_DATE, t1.REWARD, t1.INTEGRAL_DATE, t1.PERSONAL, t1.FOUNDATIONS_CONTENT, t1.PERSONAL_CONTENT, t1.VERSION, t1.REWARD_CONTENT, t1.ID, t1.CREATED_DEPT, t1.ORG_IDENTITY, t1.FOUNDATIONS, t1.LAST_UPDATE_IP, t1.INTEGRAL_CONTENT, t1.DATA_1, t1.SEX, t1.PARTY_ID, t1.PARTY_NAME, t1.ID_NUMBER from INTEGRAL t1 left join sys_user t2 on t1.user_id = t2.id
t1.creation_date = (select MAX(t3.creation_date) from INTEGRAL t3 where t3.user_id = t1.user_id) and ${s}
and
and t1.CREATED_BY = #{bean.createdBy}
and t1.LAST_UPDATED_BY = #{bean.lastUpdatedBy}
and t1.PUNISH = #{bean.punish}
and t1.FK_SUB_COL_ID like concat(concat('%',#{bean.fkSubColId}),'%')
and t1.PUNISH_CONTENT like concat(concat('%',#{bean.punishContent}),'%')
and t1.CREATION_DATE >= #{bean.creationDateBegin}
and t1.CREATION_DATE <= #{bean.creationDateEnd}
and t1.LAST_UPDATE_DATE >= #{bean.lastUpdateDateBegin}
and t1.LAST_UPDATE_DATE <= #{bean.lastUpdateDateEnd}
and t1.REWARD = #{bean.reward}
and t1.INTEGRAL_DATE >= #{bean.integralDateBegin}
and t1.INTEGRAL_DATE <= #{bean.integralDateEnd}
and t1.PERSONAL = #{bean.personal}
and t1.FOUNDATIONS_CONTENT like concat(concat('%',#{bean.foundationsContent}),'%')
and t1.PERSONAL_CONTENT like concat(concat('%',#{bean.personalContent}),'%')
and t1.VERSION = #{bean.version}
and t1.REWARD_CONTENT like concat(concat('%',#{bean.rewardContent}),'%')
and t1.ID = #{bean.id}
and t1.CREATED_DEPT = #{bean.createdDept}
and t1.FOUNDATIONS = #{bean.foundations}
and t1.LAST_UPDATE_IP = #{bean.lastUpdateIp}
and t1.INTEGRAL_CONTENT = #{bean.integralContent}
and t1.DATA_1 like concat(concat('%',#{bean.data1}),'%')
and t1.USER_ID like concat(concat('%',#{bean.userId}),'%')
and t1.SEX like concat(concat('%',#{bean.sex}),'%')
and t1.PARTY_ID like concat(concat('%',#{bean.partyId}),'%')
and t1.PARTY_NAME like concat(concat('%',#{bean.partyName}),'%')
and t1.ID_NUMBER like concat(concat('%',#{bean.idNumber}),'%')
and t2.NO like concat(concat('%',#{bean.userNO}),'%')
and to_char(t1.INTEGRAL_DATE,'yyyy') = to_char(to_date(#{bean.integralDate},'yyyy-MM-dd'),'yyyy')

select

from INTEGRAL t1
